class Solution:
    def canPartitionKSubsets(self, nums: List[int], k: int) -> bool:
        total = sum(nums)
        if total % k != 0:
            return False
        target = total // k
        if k == 1:
            return True
        nums.sort(reverse=True)
        if any(num > target for num in nums):
            return False
        subsets = [0] * k

        def backtrack(index):
            if index == len(nums):
                return True
            current = nums[index]
            for i in range(k):
                if subsets[i] + current > target:
                    continue
                if i > 0 and subsets[i] == subsets[i-1]:
                    continue
                subsets[i] += current
                if backtrack(index + 1):
                    return True
                subsets[i] -= current
            return False

        return backtrack(0)

